function sql(value) {
  if (value === undefined || value === null || value === "") return "NULL";
  if (typeof value === "boolean") return value ? "1" : "0";
  if (typeof value === "number" && Number.isFinite(value)) return String(value);

  return "'" + String(value)
    .replace(/\\/g, "\\\\")
    .replace(/'/g, "''") + "'";
}

function sqlText(value) {
  if (value === undefined || value === null) return "NULL";

  return "'" + String(value)
    .replace(/\\/g, "\\\\")
    .replace(/'/g, "''") + "'";
}

function sqlJson(value) {
  const text = JSON.stringify(value ?? {});
  return "CAST(" + sqlText(text) + " AS JSON)";
}

function enumOrNull(value) {
  return value ? sql(value) : "NULL";
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = String(value || "").trim().toLowerCase();

  if (["1", "true", "sim", "yes", "t"].includes(text)) return true;
  if (["0", "false", "nao", "não", "no", "f"].includes(text)) return false;

  return false;
}

function safeNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function cleanString(value) {
  if (value === undefined || value === null) return "";

  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return "";
    }
  }

  return String(value).trim();
}

function normalizeText(value) {
  return cleanString(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function parseMaybeJson(value, fallback) {
  if (value === undefined || value === null || value === "") return fallback;
  if (typeof value === "object") return value;

  try {
    return JSON.parse(value);
  } catch (e) {
    return fallback;
  }
}

function parseArray(value) {
  const parsed = parseMaybeJson(value, []);
  return Array.isArray(parsed) ? parsed : [];
}

function enumValue(value, allowed, fallback, path = "") {
  const v = cleanString(value);

  if (allowed.includes(v)) return v;

  if (v && path) {
    queryWarnings.push({
      path,
      raw: v,
      result: fallback,
      reason: "enum_invalido_usado_fallback"
    });
  }

  return fallback;
}

function sqlDateOrNull(value, path = "") {
  const v = cleanString(value);

  if (!v) return "NULL";

  if (/^\d{4}-\d{2}-\d{2}$/.test(v)) {
    return sql(v);
  }

  if (/^\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2}$/.test(v)) {
    return sql(v);
  }

  queryWarnings.push({
    path,
    raw: v,
    result: "NULL",
    reason: "data_nao_iso_descartada_para_evitar_erro_mysql"
  });

  return "NULL";
}

function normalizeMessages(value) {
  const arr = parseArray(value)
    .map(cleanString)
    .filter(Boolean);

  if (arr.length > 4) {
    queryWarnings.push({
      path: "inputs.mensagens_resposta",
      raw: arr.length,
      result: arr.length,
      reason: "mais_de_4_mensagens_sem_corte_automatico"
    });
  }

  return arr;
}

