  deve_enviar_guia: toBool(inputs.deve_enviar_guia),
  deve_solicitar_pagamento: false,
  deve_consultar_agenda: false,
  deve_criar_pre_reserva: false,
  deve_encerrar_conversa: deveEncerrarConversa,
  resumo_interno_repasse: repasse
};

const payloadUltimaResposta = {
  output: outputBruna,

  proxima_acao: proximaAcao,

  should_reply: shouldReply,
  motivo_bloqueio_envio: motivoBloqueioEnvio,

  turn_signals: {
    ...(inputs.turn_signals || {}),
    pediu_preco: turnSignals.pediu_preco === true,
    insistiu_preco: turnSignals.insistiu_preco === true,
    lead_pretende_castrar: turnSignals.lead_pretende_castrar === true,
    lead_nao_pretende_castrar: turnSignals.lead_nao_pretende_castrar === true,
    lead_informou_castrado_sim: turnSignals.lead_informou_castrado_sim === true,
    lead_informou_castrado_nao: turnSignals.lead_informou_castrado_nao === true,
    lead_finalizou_atendimento: turnSignals.lead_finalizou_atendimento === true
  },

  bruna_system_guard: brunaSystemGuard,
  bruna_override: brunaOverride,

  warnings: [
    ...(Array.isArray(debugContext.warnings) ? debugContext.warnings : []),
    ...(Array.isArray(debugContext.race_guard?.warnings) ? debugContext.race_guard.warnings : []),
    ...queryWarnings
  ],

  debug_context: debugContext
};

const origemJson = {
  origem_execucao: ctx.origem_execucao || "",
  sessionId: ctx.sessionId || "",
  run_mode: runMode,
  should_reply: shouldReply,
  motivo_bloqueio_envio: motivoBloqueioEnvio
};

const inputDebugJson = {
  message,
  inputs: {
    ...inputs,
    resumo_lead: resumo,
    resumo_interno_repasse: repasse,
    caes_json: caesJson,
