const raw = $input.first().json || {};

function getNodeJson(nodeName) {
  try {
    return $(nodeName).first().json || {};
  } catch (e) {
    return {};
  }
}

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function isNonEmptyObject(value) {
  return isObject(value) && Object.keys(value).length > 0;
}

function clone(value) {
  return JSON.parse(JSON.stringify(value || {}));
}

function cleanString(value) {
  if (value === undefined || value === null) return "";

  if (typeof value === "object") {
    try {
      return JSON.stringify(value);
    } catch (e) {
      return "";
    }
  }

  return String(value).trim();
}

function normalizeText(value) {
  return cleanString(value)
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function firstObject(...values) {
  for (const value of values) {
    if (isNonEmptyObject(value)) return value;
  }

  return {};
}

function firstFilled(...values) {
  for (const value of values) {
    const text = cleanString(value);
    if (text !== "") return text;
  }

  return "";
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = normalizeText(value);

  if (["1", "true", "sim", "yes", "t"].includes(text)) return true;
  if (["0", "false", "nao", "não", "no", "f"].includes(text)) return false;

  return false;
}

function parseArray(value) {
  if (Array.isArray(value)) return value;

  if (typeof value === "string" && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  return [];
}

function parseJsonFlexible(value) {
  if (value === undefined || value === null) return {};
  if (typeof value === "object") return value;

  let text = String(value).trim();

  text = text
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/i, "")
    .replace(/```$/i, "")
    .trim();

  const firstBrace = text.indexOf("{");
  const lastBrace = text.lastIndexOf("}");

  if (firstBrace >= 0 && lastBrace > firstBrace) {
    text = text.slice(firstBrace, lastBrace + 1);
  }

  try {
    return JSON.parse(text);
  } catch (error) {
    return {
      __parse_error: true,
      __parse_error_message: error.message,
      __raw_text: value
    };
  }
}

function unwrapBrunaOutput(value) {
  const parsed = parseJsonFlexible(value);

  if (!isObject(parsed)) {
    return {
      bruna: {},
      parse_error: true,
      raw_parsed: parsed
    };
  }

  if (parsed.__parse_error === true) {
    return {
      bruna: parsed,
      parse_error: true,
      raw_parsed: parsed
    };
  }

  if (typeof parsed.output === "string") {
    const nested = parseJsonFlexible(parsed.output);

    if (nested.__parse_error === true) {
      return {
        bruna: nested,
        parse_error: true,
        raw_parsed: nested
      };
    }

    if (isObject(nested)) {
      let merged = {
        ...parsed,
        ...nested
      };

      delete merged.output;

      if (isObject(nested.output)) {
        merged = {
          ...merged,
          ...nested.output
        };

        delete merged.output;
      }

      return {
        bruna: merged,
        parse_error: false,
        raw_parsed: parsed
      };
    }
  }

  if (isObject(parsed.output)) {
    let merged = {
      ...parsed,
      ...parsed.output
    };

    delete merged.output;

    if (isObject(parsed.output.output)) {
      merged = {
        ...merged,
        ...parsed.output.output
      };

      delete merged.output;
    }

    return {
      bruna: merged,
      parse_error: false,
      raw_parsed: parsed
    };
  }

  for (const key of ["text", "response", "chatOutput"]) {
    if (typeof parsed[key] === "string") {
      const nested = parseJsonFlexible(parsed[key]);

      if (!nested.__parse_error && isObject(nested)) {
        let merged = {
          ...parsed,
          ...nested
        };

        delete merged[key];

        if (isObject(nested.output)) {
          merged = {
            ...merged,
            ...nested.output
          };

          delete merged.output;
        }

        return {
          bruna: merged,
          parse_error: false,
          raw_parsed: parsed
        };
      }
    }
  }

  return {
    bruna: parsed,
    parse_error: false,
    raw_parsed: parsed
  };
}

const warnings = [];

function enumValue(value, allowed, fallback, path = "") {
  const text = cleanString(value);

  if (allowed.includes(text)) return text;

  if (text && path) {
    warnings.push({
      path,
      raw: text,
      result: fallback,
      reason: "enum_invalido_usado_fallback"
    });
  }

  return fallback;
}

function meaningful(value) {
  const text = cleanString(value);
  const normalized = normalizeText(text);

  return Boolean(
    text &&
    ![
      "nao_informado",
      "nao informado",
      "não informado",
      "nao_definido",
      "nao definido",
      "não definido",
      "nao_se_aplica",
      "nao se aplica",
      "não se aplica",
      "indefinido",
      "null",
      "undefined"
    ].includes(normalized)
  );
}

function normalizeEnum(value, allowed, fallback) {
  const text = cleanString(value);
  return allowed.includes(text) ? text : fallback;
}

function emptyDog() {
  return {
    nome: "",
    idade_anos: "",
    idade_texto: "",
    raca: "",
    raca_canonica: "",
    porte: "nao_definido",
    sexo: "nao_informado",
    castrado: "nao_informado",
    no_cio: "nao_informado",
    vacinas_ok: "nao_informado",
    antipulgas_ok: "nao_informado",
    vermifugacao_ok: "nao_informado",
    perfil_comportamental: "nao_informado",
    comportamento_observacoes: "",
    possui_relatorio_veterinario: "nao_informado",
    observacoes: "",
    regras_raca: {}
  };
}

function normalizeDog(cao = {}) {
  const sexo = normalizeEnum(
    cao.sexo,
    ["macho", "femea", "nao_informado"],
    "nao_informado"
  );

  const dog = {
    ...emptyDog(),

    nome: cleanString(cao.nome),
    idade_anos: cleanString(cao.idade_anos),
    idade_texto: cleanString(cao.idade_texto),
    raca: cleanString(cao.raca),
    raca_canonica: cleanString(cao.raca_canonica),

    porte: normalizeEnum(
      cao.porte,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    sexo,

    castrado: normalizeEnum(
      cao.castrado,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    no_cio: sexo === "macho"
      ? "nao_se_aplica"
      : normalizeEnum(
          cao.no_cio,
          ["sim", "nao", "nao_se_aplica", "nao_informado"],
          "nao_informado"
        ),

    vacinas_ok: normalizeEnum(
      cao.vacinas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    antipulgas_ok: normalizeEnum(
      cao.antipulgas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    vermifugacao_ok: normalizeEnum(
      cao.vermifugacao_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    perfil_comportamental: normalizeEnum(
      cao.perfil_comportamental,
      [
        "nao_informado",
        "tranquilo",
        "sociavel",
        "seletivo",
        "reativo_leve",
        "reativo_alto",
        "agressivo",
        "indeterminado"
      ],
      "nao_informado"
    ),

    comportamento_observacoes: cleanString(cao.comportamento_observacoes),

    possui_relatorio_veterinario: normalizeEnum(
      cao.possui_relatorio_veterinario,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    observacoes: cleanString(cao.observacoes),
    regras_raca: isObject(cao.regras_raca) ? cao.regras_raca : {}
  };

  return dog;
}

function hasDogIdentity(cao = {}) {
  const dog = normalizeDog(cao);

  return Boolean(
    meaningful(dog.nome) ||
    meaningful(dog.idade_anos) ||
    meaningful(dog.idade_texto) ||
    meaningful(dog.raca) ||
    meaningful(dog.raca_canonica) ||
    ["macho", "femea"].includes(dog.sexo)
  );
}

function normalizeDogs(value) {
  return parseArray(value)
    .filter(isObject)
    .map(normalizeDog)
    .filter(hasDogIdentity);
}

function titleCaseName(value) {
  const raw = cleanString(value);

  if (!raw) return "";

  return raw
    .toLowerCase()
    .split(/\s+/)
    .filter(Boolean)
    .map(part => part.charAt(0).toUpperCase() + part.slice(1))
    .join(" ");
}

function isCastratedYesText(text) {
  const t = normalizeText(text);

  if (!t) return false;

  if (/(nao|não)\s+(e|eh|é)?\s*castrad/.test(t)) return false;
  if (/ainda\s+(nao|não).{0,12}castrad/.test(t)) return false;
  if (/(nao|não)\s+foi\s+castrad/.test(t)) return false;

  return /(^|\s)(e|eh|é|ja e|já é|ja eh|já eh|ele e|ele é|ela e|ela é|sim e|sim é|sim eh).{0,12}castrad|castrad[oa]\s+sim|ja\s+castrad|já\s+castrad/.test(t);
}

function isCastratedNoText(text) {
  const t = normalizeText(text);

  if (!t) return false;

  return /((nao|não)\s+(e|eh|é)?\s*castrad|(nao|não)\s+castrad|ainda\s+(nao|não).{0,12}castrad|(nao|não)\s+foi\s+castrad)/.test(t);
}

function detectSexFromText(text) {
  const t = normalizeText(text);

  if (/\b(femea|fêmea|cadela|cadelinha)\b/.test(t)) return "femea";
  if (/\b(macho|machinho)\b/.test(t)) return "macho";

  return "nao_informado";
}

function detectCastrationFromText(text) {
  if (isCastratedNoText(text)) return "nao";
  if (isCastratedYesText(text)) return "sim";
  return "nao_informado";
}

function extractAgeFromText(text) {
  const t = normalizeText(text);

  const anosMatch = t.match(/\b(\d{1,2})\s*anos?\b/);
  if (anosMatch) {
    return {
      idade_anos: String(anosMatch[1]),
      idade_texto: `${anosMatch[1]} anos`
    };
  }

  const mesesMatch = t.match(/\b(\d{1,2})\s*mes(?:es)?\b/);
  if (mesesMatch) {
    return {
      idade_anos: "",
      idade_texto: `${mesesMatch[1]} meses`
    };
  }

  return {
    idade_anos: "",
    idade_texto: ""
  };
}

function removeKnownDogFragments(text, nome = "") {
  let out = cleanString(text);

  if (nome) {
    out = out.replace(
      new RegExp(`^\\s*${nome.replace(/[.*+?^${}()|[\]\\]/g, "\\$&")}\\s*,?`, "i"),
      " "
    );
  }

  out = out
    .replace(/\b\d{1,2}\s*anos?\b/gi, " ")
    .replace(/\b\d{1,2}\s*mes(?:es)?\b/gi, " ")
    .replace(/\b(femea|fêmea|macho|cadela|cadelinha|machinho)\b/gi, " ")
    .replace(/\b(n[aã]o\s+)?castrad[oa]\b/gi, " ")
    .replace(/\b(ja|já|eh|é|e)\b\s*castrad[oa]\b/gi, " ")
    .replace(/\b(nao|não)\b/gi, " ")
    .replace(/[,;|]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();

  return out;
}

function extractDogFromStructuredCurrentMessage(text) {
  const original = cleanString(text);
  const t = normalizeText(original);

  if (!original) return null;
  if (t.includes("melhoria bruna")) return null;

  const hasAge = /\b\d{1,2}\s*(ano|anos|mes|meses)\b/.test(t);
  const sexo = detectSexFromText(original);
  const hasSex = sexo === "macho" || sexo === "femea";

  if (!hasAge || !hasSex) return null;

  const parts = original
    .split(",")
    .map(part => cleanString(part))
    .filter(Boolean);

  let nome = "";

  if (parts.length >= 2) {
    const first = parts[0] || "";
    const firstNorm = normalizeText(first);

    if (
      first &&
      !/\b\d{1,2}\s*(ano|anos|mes|meses)\b/.test(firstNorm) &&
      !/\b(macho|femea|fêmea)\b/.test(firstNorm) &&
      !/castrad/.test(firstNorm)
    ) {
      nome = titleCaseName(first);
    }
  }

  if (!nome) {
    const firstToken = original
      .split(/[\s,]+/)
      .map(part => cleanString(part))
      .filter(Boolean)[0] || "";

    const firstTokenNorm = normalizeText(firstToken);

    if (
      firstToken &&
      !["macho", "femea", "fêmea", "cadela", "cadelinha"].includes(firstTokenNorm) &&
      !/^\d+$/.test(firstTokenNorm)
    ) {
      nome = titleCaseName(firstToken);
    }
  }

  const age = extractAgeFromText(original);
  const castrado = detectCastrationFromText(original);

  let raca = "";

  if (parts.length >= 3) {
    const racaCandidate = parts
      .filter(part => {
        const p = normalizeText(part);

        if (!p) return false;
        if (nome && p === normalizeText(nome)) return false;
        if (/\b\d{1,2}\s*(ano|anos|mes|meses)\b/.test(p)) return false;
        if (/\b(macho|femea|fêmea|cadela|cadelinha)\b/.test(p)) return false;
        if (/castrad/.test(p)) return false;

        return true;
      })
      .pop();

    raca = cleanString(racaCandidate || "");
  }

  if (!raca) {
    raca = removeKnownDogFragments(original, nome);
  }

  const dog = normalizeDog({
    nome,
    idade_anos: age.idade_anos,
    idade_texto: age.idade_texto,
    raca,
    raca_canonica: "",
    porte: "nao_definido",
    sexo,
    castrado,
    no_cio: sexo === "macho" ? "nao_se_aplica" : "nao_informado",
    vacinas_ok: "nao_informado",
    antipulgas_ok: "nao_informado",
    vermifugacao_ok: "nao_informado",
    perfil_comportamental: "nao_informado",
    comportamento_observacoes: "",
    possui_relatorio_veterinario: age.idade_anos && Number(age.idade_anos) < 10
      ? "nao_se_aplica"
      : "nao_informado",
    observacoes: "",
    regras_raca: {}
  });

  return hasDogIdentity(dog) ? dog : null;
}

function idadeEmMeses(cao = {}) {
  const dog = normalizeDog(cao);

  const idadeAnosRaw = cleanString(dog.idade_anos).replace(",", ".");
  const idadeTexto = normalizeText(dog.idade_texto);

  const idadeAnos = Number(idadeAnosRaw);

  if (Number.isFinite(idadeAnos) && idadeAnos > 0) {
    return Math.round(idadeAnos * 12);
  }

  const mesesMatch = idadeTexto.match(/(\d{1,2})\s*(mes|meses)/);
  if (mesesMatch) return Number(mesesMatch[1]);

  const anosMatch = idadeTexto.match(/(\d{1,2})\s*(ano|anos)/);
  if (anosMatch) return Number(anosMatch[1]) * 12;

  return null;
}

function isAdultMale(cao = {}) {
  const dog = normalizeDog(cao);
  const meses = idadeEmMeses(dog);

  return (
    dog.sexo === "macho" &&
    meses !== null &&
    meses >= 8
  );
}

function isAdultMaleCastrationUnknown(cao = {}) {
  const dog = normalizeDog(cao);

  return (
    isAdultMale(dog) &&
    !["sim", "nao"].includes(dog.castrado)
  );
}

function isAdultMaleNonCastrated(cao = {}) {
  const dog = normalizeDog(cao);

  return (
    isAdultMale(dog) &&
    dog.castrado === "nao"
  );
}

function isFemaleNonCastrated(cao = {}) {
  const dog = normalizeDog(cao);

  return (
    dog.sexo === "femea" &&
    dog.castrado === "nao"
  );
}

function isFemaleInHeat(cao = {}) {
  const dog = normalizeDog(cao);

  return (
    dog.sexo === "femea" &&
    dog.no_cio === "sim"
  );
}

function hasAdultMaleNonCastrated(caes = []) {
  return normalizeDogs(caes).some(isAdultMaleNonCastrated);
}

function hasAdultMaleCastrationUnknown(caes = []) {
  return normalizeDogs(caes).some(isAdultMaleCastrationUnknown);
}

function hasFemaleNonCastrated(caes = []) {
  return normalizeDogs(caes).some(isFemaleNonCastrated);
}

function getFirstAdultMaleUnknown(caes = []) {
  return normalizeDogs(caes).find(isAdultMaleCastrationUnknown) || {};
}

function getFirstAdultMaleNonCastrated(caes = []) {
  return normalizeDogs(caes).find(isAdultMaleNonCastrated) || {};
}

function getFirstFemaleNonCastrated(caes = []) {
  return normalizeDogs(caes).find(isFemaleNonCastrated) || {};
}

function dogNameOrPronoun(cao = {}, fallback = "ele") {
  const dog = normalizeDog(cao);
  return meaningful(dog.nome) ? dog.nome : fallback;
}

function labelIndicaHumanoAssumiu(labels = []) {
  return labels.some(label => {
    const l = normalizeText(label);

    return (
      l === "01 humano assumiu" ||
      l === "humano assumiu" ||
      l.includes("humano assumiu") ||
      l === "01 em atendimento" ||
      l.includes("em atendimento humano") ||
      l === "01 humano assumido" ||
      l === "01-humano-assumiu"
    );
  });
}

function stripDogCopies(obj = {}) {
  if (!isObject(obj)) return {};

  const out = { ...obj };

  delete out.caes_json;
  delete out.quantidade_caes;
  delete out.regras_raca;
  delete out.caes;
