function normalizeMessages(messages) {
  const arr = Array.isArray(messages) ? messages : [];

  const normalized = arr
    .map(cleanString)
    .filter(Boolean);

  if (normalized.length > 4) {
    warnings.push({
      path: "mensagens_resposta",
      raw: normalized.length,
      result: normalized.length,
      reason: "mais_de_4_mensagens_sem_corte_automatico"
    });
  }

  return normalized;
}

function hasConversationContinuation(messages, flags = {}) {
  if (!messages.length) return false;

  if (
    flags.deve_repassar_humano ||
    flags.deve_encerrar_conversa ||
    flags.deve_solicitar_pagamento
  ) {
    return true;
  }

  const last = cleanString(messages[messages.length - 1]);

  if (last.includes("?")) return true;

  const normalized = normalizeText(last);

  const deadEndPatterns = [
    "fico a disposicao",
    "qualquer duvida estou aqui",
    "quando quiser me avise",
    "estou a disposicao"
  ];

  return !deadEndPatterns.some(pattern => normalized.includes(pattern));
}

function similarity(a, b) {
  const tokensA = new Set(normalizeText(a).split(" ").filter(Boolean));
  const tokensB = new Set(normalizeText(b).split(" ").filter(Boolean));

  if (!tokensA.size || !tokensB.size) return 0;

  let intersection = 0;

  for (const token of tokensA) {
    if (tokensB.has(token)) intersection++;
  }

  const union = new Set([...tokensA, ...tokensB]).size;
  return union ? intersection / union : 0;
}

function hasRepeatedConfirmation(messages, lastMessage) {
  const joined = normalizeText(messages.join(" "));
  const last = normalizeText(lastMessage);

  return (
    joined.includes("obrigada por confirmar") && last.includes("obrigada por confirmar")
  ) || (
    joined.includes("obrigado por confirmar") && last.includes("obrigado por confirmar")
  );
}

function compactDogName(dog = {}) {
  const nome = cleanString(dog.nome);
  return nome ? `do ${nome}` : "dele";
}

function dedupeCandidates(candidates = []) {
  const seen = new Set();
  const out = [];

  for (const item of parseArray(candidates)) {
    const name = cleanString(item.raca_canonica || item.nome || item.raca);

    if (!name) continue;

    const key = normalizeText(name);

    if (!key || seen.has(key)) continue;

    seen.add(key);
    out.push(name);

    if (out.length >= 3) break;
  }

  return out;
}

function buildRaceConfirmMessage(dog = {}) {
  const regra = dog.regras_raca || {};
  const original = cleanString(regra.raca_original || dog.raca || "a raça informada");
  const candidates = dedupeCandidates(regra.racas_candidatas);

  if (candidates.length >= 2) {
    const list =
      candidates.length === 2
        ? `${candidates[0]} ou ${candidates[1]}`
        : `${candidates.slice(0, -1).join(", ")} ou ${candidates[candidates.length - 1]}`;

    return `Pra eu não cadastrar errado: qual é a raça exata ${compactDogName(dog)}? Para “${original}”, apareceram possibilidades como ${list}.`;
  }

  return `Pra eu não cadastrar errado: qual é a raça exata ${compactDogName(dog)}? O nome “${original}” precisa ser confirmado antes de eu te orientar sobre os próximos passos.`;
}

function raceGuard(caesJson = []) {
  const dogs = normalizeDogs(caesJson);

  const pending = [];
  const blocked = [];

  for (const dog of dogs) {
    const regra = isObject(dog.regras_raca) ? dog.regras_raca : {};
    const status = cleanString(regra.status_raca);
    const confidence = cleanString(regra.nivel_confianca_raca);

    const needsConfirm =
      status === "precisa_confirmar_raca" ||
      status === "sem_raca_informada" ||
      toBool(regra.deve_confirmar_raca) ||
      toBool(regra.precisa_confirmacao_antes_decisao) ||
      confidence === "baixa" ||
      regra.decisao_raca_conclusiva === false;

    const isBlocked =
      status === "bloqueado_potencial_dano" &&
      !needsConfirm &&
      toBool(regra.decisao_raca_conclusiva);

    if (needsConfirm) {
      pending.push(dog);
      continue;
    }

    if (isBlocked) {
      blocked.push(dog);
    }
  }

  return {
    hasPendingRaceConfirmation: pending.length > 0,
    pendingRaceDogs: pending,
    hasConclusiveBreedBlock: blocked.length > 0,
    blockedRaceDogs: blocked
  };
}

