function normalizeDog(dog = {}) {
  const regrasRaca = isObject(dog.regras_raca)
    ? normalizeRegrasRaca(dog.regras_raca)
    : {};

  const sexo = normalizeEnum(
    dog.sexo,
    ["macho", "femea", "nao_informado"],
    "nao_informado"
  );

  const noCio = sexo === "macho"
    ? "nao_se_aplica"
    : normalizeEnum(
        dog.no_cio,
        ["sim", "nao", "nao_se_aplica", "nao_informado"],
        "nao_informado"
      );

  return {
    ...emptyDog(),

    nome: publicFacingText(dog.nome),
    idade_anos: String(dog.idade_anos || ""),
    idade_texto: publicFacingText(dog.idade_texto),
    raca: publicFacingText(dog.raca),
    raca_canonica: publicFacingText(dog.raca_canonica),

    porte: normalizeEnum(
      dog.porte,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    sexo,

    castrado: normalizeEnum(
      dog.castrado,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    no_cio: noCio,

    vacinas_ok: normalizeEnum(
      dog.vacinas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    antipulgas_ok: normalizeEnum(
      dog.antipulgas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    vermifugacao_ok: normalizeEnum(
      dog.vermifugacao_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    perfil_comportamental: normalizeEnum(
      dog.perfil_comportamental,
      [
        "nao_informado",
        "tranquilo",
        "sociavel",
        "seletivo",
        "reativo_leve",
        "reativo_alto",
        "agressivo",
        "indeterminado"
      ],
      "nao_informado"
    ),

    comportamento_observacoes: publicFacingText(dog.comportamento_observacoes),

    possui_relatorio_veterinario: normalizeEnum(
      dog.possui_relatorio_veterinario,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    observacoes: publicFacingText(dog.observacoes),
    regras_raca: regrasRaca
  };
}

function normalizeDogs(value) {
  const parsed = parseMaybeJson(value, []);

  if (!Array.isArray(parsed)) return [];

  return parsed
    .filter(dog => dog && typeof dog === "object")
    .map(normalizeDog);
}

function dogHasRealIdentity(dog = {}) {
  if (!isObject(dog)) return false;

  return Boolean(
    publicFacingText(dog.nome) ||
    publicFacingText(dog.raca) ||
    publicFacingText(dog.raca_canonica) ||
    publicFacingText(dog.idade_anos) ||
    publicFacingText(dog.idade_texto) ||
    ["macho", "femea"].includes(publicFacingText(dog.sexo))
  );
}

function dogKey(dog = {}) {
  const nome = normalizeText(dog.nome);
  const raca = normalizeText(dog.raca_canonica || dog.raca);
  const idade = normalizeText(dog.idade_anos || dog.idade_texto);
  const sexo = normalizeText(dog.sexo);

  if (nome) return `nome:${nome}`;

  return [
    `raca:${raca}`,
    `idade:${idade}`,
    `sexo:${sexo}`
  ].join("|");
}

function mergeDog(base = {}, incoming = {}) {
  const out = { ...base };

  for (const [key, value] of Object.entries(incoming || {})) {
    if (key === "regras_raca") continue;

    const valueText = publicFacingText(value);
    const currentText = publicFacingText(out[key]);

    if (!valueText) continue;

    if (!currentText) {
      out[key] = value;
      continue;
    }

    if (
      ["nao_informado", "nao_definido", "nao_se_aplica"].includes(normalizeText(currentText)) &&
      !["nao_informado", "nao_definido", "nao_se_aplica"].includes(normalizeText(valueText))
    ) {
      out[key] = value;
    }
  }

  if (isObject(base.regras_raca) && Object.keys(base.regras_raca).length) {
    out.regras_raca = base.regras_raca;
  } else if (isObject(incoming.regras_raca) && Object.keys(incoming.regras_raca).length) {
    out.regras_raca = incoming.regras_raca;
  } else {
    out.regras_raca = {};
  }

  return normalizeDog(out);
}

function sanitizeDogs(dogs = []) {
  const input = Array.isArray(dogs) ? dogs : [];
  const result = [];
  const index = new Map();

  for (const rawDog of input) {
    if (!isObject(rawDog)) continue;

    const dog = normalizeDog(rawDog);

    if (!dogHasRealIdentity(dog)) continue;

    const key = dogKey(dog);

    if (!index.has(key)) {
      index.set(key, result.length);
      result.push(dog);
      continue;
    }

    const pos = index.get(key);
    result[pos] = mergeDog(result[pos], dog);
  }

  return result;
}

function sortHistory(historico = []) {
  const arr = Array.isArray(historico) ? historico : [];

  return [...arr].sort((a, b) => {
    const da = new Date(a.criado_em || 0).getTime() || 0;
    const db = new Date(b.criado_em || 0).getTime() || 0;

    if (da !== db) return da - db;

    const ia = Number(a.id || 0);
    const ib = Number(b.id || 0);

    return ia - ib;
  });
}

function getLatestMessageByType(historicoOrdenado, tipos) {
  const allowed = Array.isArray(tipos) ? tipos : [tipos];

  const last = [...historicoOrdenado]
    .reverse()
    .find(h => allowed.includes(h.tipo_registro) && publicFacingText(h.mensagem_texto));

  return publicFacingText(last?.mensagem_texto || "");
}

function extractLastQuestionOrRequest(text) {
  const value = publicFacingText(text);

  if (!value) return "";

  const sentences = value
    .match(/[^.!?]+[.!?]?/g)
    ?.map(s => s.trim())
    .filter(Boolean) || [];

  const requestPattern = /(\?|pode me|me informa|me informar|me conta|me contar|preciso saber|tamb[eé]m preciso saber|confirma|confirmar|você consegue|voce consegue|qual seria|quer que eu|posso ajudar|pretende castrar|vacinas|antipulgas|vermifugação|vermifugacao)/i;

  for (let i = sentences.length - 1; i >= 0; i--) {
    if (requestPattern.test(sentences[i])) {
      return sentences[i];
    }
  }

  return "";
}

function messageAskedPrice(text) {
  const t = normalizeText(text);

  return /(preco|preço|valor|mensalidade|diaria|diária|pacote|plano|quanto custa|quanto fica|quanto sai|valores)/.test(t);
}

function messageIsStrongPriceInsistence(text) {
  const t = normalizeText(text);

  return /(mas quanto|so quero saber|só quero saber|me passa o preco|me passa o preço|me passa o valor|qual o valor mesmo|valor mesmo|quanto fica entao|quanto fica então|e o preco|e o preço|e o valor|queria saber o valor mesmo)/.test(t);
}

function brunaAskedCastration(text) {
  const t = normalizeText(text);

  return /(pretende castrar|vai castrar|tem intencao de castrar|tem intenção de castrar|pretende fazer a castracao|pretende fazer a castração)/.test(t);
}

function brunaAskedFinalHelp(text) {
  const t = normalizeText(text);

  return /(posso ajudar com mais alguma informacao|posso ajudar com mais alguma informação|precisa de mais alguma coisa|te ajudo com mais alguma coisa|ficou alguma duvida|ficou alguma dúvida)/.test(t);
}

function leadFinishedPolitely(text) {
  const t = normalizeText(text);

  return /(nao obrigado|não obrigado|nao obrigada|não obrigada|obrigado|obrigada|sem mais|nao preciso|não preciso|por enquanto nao|por enquanto não)/.test(t);
}

function currentLeadConfirmedYes(text) {
  const t = normalizeText(text);

  return /^(sim|s|isso|confirmo|correto|pode ser|pretendo|vou sim|quero sim|claro)$/i.test(t);
}

function currentLeadSaidNo(text) {
