  caes_depois_patch: caesMesclados.length,
  quantidade_caes_para_consulta: caesParaConsulta.length,
  warnings_consulta_raca: warnings
};

return [{ json: ctx }];

const item = $json || {};

function isObject(value) {
  return value && typeof value === "object" && !Array.isArray(value);
}

function clone(value) {
  return JSON.parse(JSON.stringify(value || {}));
}

function clean(value) {
  if (value === undefined || value === null) return "";
  return String(value).trim();
}

function norm(value) {
  return clean(value)
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\w\s]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function hasValue(value) {
  const text = clean(value);
  const normalized = norm(text);

  return Boolean(
    text &&
    ![
      "nao_informado",
      "nao informado",
      "não informado",
      "nao_definido",
      "nao definido",
      "não definido",
      "nao_se_aplica",
      "nao se aplica",
      "não se aplica",
      "indefinido",
      "null",
      "undefined"
    ].includes(normalized)
  );
}

function toBool(value) {
  if (value === true) return true;
  if (value === false) return false;
  if (value === 1) return true;
  if (value === 0) return false;

  const text = norm(value);
  if (["true", "sim", "yes", "1", "t"].includes(text)) return true;
  if (["false", "nao", "não", "no", "0", "f"].includes(text)) return false;

  return false;
}

function parseArray(value) {
  if (Array.isArray(value)) return value;

  if (typeof value === "string" && value.trim()) {
    try {
      const parsed = JSON.parse(value);
      return Array.isArray(parsed) ? parsed : [];
    } catch (e) {
      return [];
    }
  }

  return [];
}

function normalizeEnum(value, allowed, fallback) {
  const text = clean(value);
  return allowed.includes(text) ? text : fallback;
}

function normalizeDog(cao = {}) {
  const sexo = normalizeEnum(
    cao.sexo,
    ["macho", "femea", "nao_informado"],
    "nao_informado"
  );

  const normalized = {
    nome: clean(cao.nome),
    idade_anos: clean(cao.idade_anos),
    idade_texto: clean(cao.idade_texto),
    raca: clean(cao.raca),
    raca_canonica: clean(cao.raca_canonica),

    porte: normalizeEnum(
      cao.porte,
      ["mini", "pequeno", "medio", "grande", "gigante", "nao_definido"],
      "nao_definido"
    ),

    sexo,

    castrado: normalizeEnum(
      cao.castrado,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    no_cio: sexo === "macho"
      ? "nao_se_aplica"
      : normalizeEnum(
          cao.no_cio,
          ["sim", "nao", "nao_se_aplica", "nao_informado"],
          "nao_informado"
        ),

    vacinas_ok: normalizeEnum(
      cao.vacinas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    antipulgas_ok: normalizeEnum(
      cao.antipulgas_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    vermifugacao_ok: normalizeEnum(
      cao.vermifugacao_ok,
      ["sim", "nao", "nao_informado"],
      "nao_informado"
    ),

    perfil_comportamental: normalizeEnum(
      cao.perfil_comportamental,
      [
        "nao_informado",
        "tranquilo",
        "sociavel",
        "seletivo",
        "reativo_leve",
        "reativo_alto",
        "agressivo",
        "indeterminado"
      ],
      "nao_informado"
    ),

    comportamento_observacoes: clean(cao.comportamento_observacoes),

    possui_relatorio_veterinario: normalizeEnum(
      cao.possui_relatorio_veterinario,
      ["sim", "nao", "nao_se_aplica", "nao_informado"],
      "nao_informado"
    ),

    observacoes: clean(cao.observacoes),
    regras_raca: isObject(cao.regras_raca) ? cao.regras_raca : {}
  };

  return normalized;
}

function isRealDog(cao = {}) {
  const dog = normalizeDog(cao);

  return Boolean(
    hasValue(dog.nome) ||
    hasValue(dog.idade_anos) ||
    hasValue(dog.idade_texto) ||
    hasValue(dog.raca) ||
    hasValue(dog.raca_canonica) ||
    ["macho", "femea"].includes(dog.sexo)
  );
}

function getCaes() {
  const fromInputs = parseArray(item.inputs?.caes_json);
  if (fromInputs.length) return fromInputs;

  const fromRoot = parseArray(item.caes_json);
  if (fromRoot.length) return fromRoot;

  const fromPayload = parseArray(item.consulta_raca_payload?.caes_json);
  if (fromPayload.length) return fromPayload;

  return [];
}

function idadeEmMeses(cao = {}) {
  const idadeAnosRaw = clean(cao.idade_anos).replace(",", ".");
  const idadeTexto = norm(cao.idade_texto);

  const idadeAnos = Number(idadeAnosRaw);
  if (Number.isFinite(idadeAnos) && idadeAnos > 0) {
    return Math.round(idadeAnos * 12);
  }

  const mesesMatch = idadeTexto.match(/(\d{1,2})\s*(mes|meses)/);
  if (mesesMatch) return Number(mesesMatch[1]);

  const anosMatch = idadeTexto.match(/(\d{1,2})\s*(ano|anos)/);
  if (anosMatch) return Number(anosMatch[1]) * 12;

  return null;
}

function femalePronoun(cao = {}) {
  return hasValue(cao.nome) ? clean(cao.nome) : "ela";
}

function malePronoun(cao = {}) {
  return hasValue(cao.nome) ? clean(cao.nome) : "ele";
}

function isAdultMale(cao = {}) {
  const dog = normalizeDog(cao);
  const meses = idadeEmMeses(dog);

  return (
    dog.sexo === "macho" &&
    meses !== null &&
    meses >= 8
  );
}

function isAdultMaleCastrationUnknown(cao = {}) {
  const dog = normalizeDog(cao);

  return (
    isAdultMale(dog) &&
    !["sim", "nao"].includes(dog.castrado)
  );
}

function isAdultMaleNonCastrated(cao = {}) {
  const dog = normalizeDog(cao);

  return (
    isAdultMale(dog) &&
    dog.castrado === "nao"
  );
}

function isFemaleNonCastrated(cao = {}) {
