function questionTopic(text) {
  const t = norm(text);

  if (!t) return "vazio";
  if (/(raca|raça|buldog|bulldog|spitz|salsicha|dachshund|porte)/.test(t)) return "raca";
  if (/(castrad|castracao|castração|castrar)/.test(t)) return "castracao";
  if (/(idade|anos|meses|sexo|macho|femea|fêmea)/.test(t)) return "dados_basicos";
  if (/(vacina|vacinacao|vacinação|antipulga|anti pulga|vermifug|v10|tosse|antirrabica|antirrábica)/.test(t)) return "sanitario";
  if (/(convive|convivencia|convivência|outros caes|outros cães|reativ|comport|late|morde|avanca|avança|agressiv)/.test(t)) return "comportamento";
  if (/(frequencia|frequência|vezes por semana|quantas vezes|segunda|terça|terca|quarta|quinta|sexta|sabado|sábado)/.test(t)) return "frequencia_creche";
  if (/(diaria|diária|hospedagem|hotel|check in|checkin|check out|checkout|periodo|período|datas|data)/.test(t)) return "periodo_hotel";
  if (/(avaliacao|avaliação|taxa|pagamento|pix|comprovante)/.test(t)) return "avaliacao_pagamento";
  if (/(relatorio|relatório|veterinario|veterinário)/.test(t)) return "relatorio_veterinario";
  if (/(mais alguma|ajudar com mais|precisa de algo|ficou alguma)/.test(t)) return "finalizacao";

  return "outro";
}

function extractBrunaMessagesFromHistory(history) {
  const lines = String(history || "")
    .split(/\n+/)
    .map(line => clean(line))
    .filter(Boolean);

  return lines
    .filter(line => {
      const l = norm(line);
      return (
        l.includes("bruna:") ||
        l.includes("mensagem bruna") ||
        l.includes("ultima mensagem da bruna") ||
        l.startsWith("bruna ")
      );
    })
    .map(line => line.replace(/^.*?bruna\s*:?\s*/i, "").trim())
    .filter(Boolean);
}

function countRecentTopicRepeats(topic, brunaMessages = []) {
  if (!topic || topic === "outro" || topic === "vazio") return 0;

  const recent = brunaMessages.slice(-8);
  return recent.filter(msg => questionTopic(msg) === topic).length;
}

function leadComplainedAboutRepeat(text) {
  const t = norm(text);

  return /(ja respondi|já respondi|respondi isso|ja falei|já falei|voce perguntou isso|você perguntou isso|perguntando de novo|de novo|mesma pergunta|ja disse|já disse)/.test(t);
}

function shouldBlockImprovementFeedback(text) {
  const t = norm(text);

  return (
    t.includes("melhoria bruna") ||
    t.includes("[melhoria bruna]") ||
    t.includes("m melhoria bruna") ||
    t.includes("feedback bruna")
  );
}

function normalizeFrequency(text) {
  const t = norm(text);

  if (/(^1x\b|uma vez|1 vez)/.test(t)) return "1x por semana";
  if (/(^2x\b|duas vezes|2 vezes|segunda e quinta)/.test(t)) return "2x por semana";
  if (/(^3x\b|tres vezes|três vezes|3 vezes|segunda quarta e sexta|segunda, quarta e sexta)/.test(t)) return "3x por semana";
  if (/(^4x\b|quatro vezes|4 vezes|segunda a quinta)/.test(t)) return "4x por semana";
  if (/(^5x\b|cinco vezes|5 vezes|segunda a sexta|todos os dias|todo dia)/.test(t)) return "5x por semana";

  if (/^(1|um|uma)$/.test(t)) return "1x por semana";
  if (/^(2|dois|duas)$/.test(t)) return "2x por semana";
  if (/^(3|tres|três)$/.test(t)) return "3x por semana";
  if (/^(4|quatro)$/.test(t)) return "4x por semana";
  if (/^(5|cinco)$/.test(t)) return "5x por semana";

  return "";
}

function isFrequencyOnly(text) {
  const t = norm(text);
  if (!normalizeFrequency(text)) return false;

  return /^(\d+x|\d|um|uma|dois|duas|tres|três|quatro|cinco|uma vez|duas vezes|tres vezes|três vezes|quatro vezes|cinco vezes|segunda|terca|terça|quarta|quinta|sexta|sabado|sábado|segunda a sexta|segunda a quinta|segunda e quinta|segunda quarta e sexta|segunda, quarta e sexta|todos os dias|todo dia)(\s+por semana)?$/.test(t);
}

function parseSimplePeriodDays(text) {
  const t = norm(text);
  const match = t.match(/(?:de\s*)?(\d{1,2})\s*a\s*(\d{1,2})/);

  if (!match) return null;

  const start = Number(match[1]);
  const end = Number(match[2]);

  if (!Number.isFinite(start) || !Number.isFinite(end)) return null;
  if (start <= 0 || end <= 0 || end <= start) return null;

  return {
    start_day: start,
    end_day: end,
    diarias: end - start
  };
}

function isHotelPeriod(text) {
  const t = norm(text);

  return /(\d{1,2}\s*a\s*\d{1,2}|de\s*\d{1,2}\s*a\s*\d{1,2}|checkin|check in|checkout|check out|hospedagem|hotel|feriado|sao joao|são joão|janeiro|fevereiro|marco|março|abril|maio|junho|julho|agosto|setembro|outubro|novembro|dezembro)/.test(t);
}

function racaStatus(cao = {}) {
  return clean(cao.regras_raca?.status_raca);
}

function racaConclusiva(cao = {}) {
  return cao.regras_raca?.decisao_raca_conclusiva === true;
}

function racaPendente(cao = {}) {
  const status = racaStatus(cao);
  const regra = isObject(cao.regras_raca) ? cao.regras_raca : {};

  return (
    status === "precisa_confirmar_raca" ||
    status === "sem_raca_informada" ||
    regra.precisa_confirmacao_antes_decisao === true ||
    regra.deve_confirmar_raca === true ||
    regra.nivel_confianca_raca === "baixa"
  );
}

function racaBloqueada(cao = {}) {
  return (
    racaStatus(cao) === "bloqueado_potencial_dano" &&
    racaConclusiva(cao) === true &&
    racaPendente(cao) !== true
  );
}

function racaOk(cao = {}) {
  return (
    racaStatus(cao) === "raca_ok" &&
    racaConclusiva(cao) === true &&
    racaPendente(cao) !== true &&
    racaBloqueada(cao) !== true
  );
}

function hasBasicDogData(cao = {}) {
  const dog = normalizeDog(cao);

  return (
    hasValue(dog.nome) &&
    (hasValue(dog.idade_anos) || hasValue(dog.idade_texto)) &&
    (hasValue(dog.raca) || hasValue(dog.raca_canonica)) &&
    ["macho", "femea"].includes(dog.sexo)
  );
}

function hasSanitario(cao = {}) {
  const dog = normalizeDog(cao);

  return (
    dog.vacinas_ok === "sim" &&
    dog.antipulgas_ok === "sim" &&
    dog.vermifugacao_ok === "sim"
  );
}

function hasComportamento(cao = {}) {
  const dog = normalizeDog(cao);

  return (
    hasValue(dog.perfil_comportamental) &&
    dog.perfil_comportamental !== "nao_informado"
  );
}

function dogEligibility(cao = {}) {
  const dog = normalizeDog(cao);

  const basic = hasBasicDogData(dog);
  const sanitario = hasSanitario(dog);
  const comportamento = hasComportamento(dog);

  const adultMaleUnknown = isAdultMaleCastrationUnknown(dog);
  const adultMaleNo = isAdultMaleNonCastrated(dog);

  const pendingBreed = racaPendente(dog);
  const blockedBreed = racaBloqueada(dog);
  const breedOk = racaOk(dog);

  const femaleInHeat = dog.sexo === "femea" && dog.no_cio === "sim";

  const ok =
    basic &&
    sanitario &&
    comportamento &&
    breedOk &&
    !pendingBreed &&
    !blockedBreed &&
    !adultMaleUnknown &&
    !adultMaleNo &&
    !femaleInHeat;

  return {
    ok,
    hasBasic: basic,
    hasSanitario: sanitario,
    hasComportamento: comportamento,

    racaOk: breedOk,
    racaPendente: pendingBreed,
    racaBloqueada: blockedBreed,

    machoAdultoCastracaoNaoInformada: adultMaleUnknown,
    machoAdultoNaoCastrado: adultMaleNo,

    femeaNaoCastrada: isFemaleNonCastrated(dog),
    femeaNoCio: femaleInHeat
  };
}

