function chooseOverride(current, incoming) {
  if (!isObject(incoming) || !Object.keys(incoming).length) return current;
  if (!isObject(current) || !Object.keys(current).length) return incoming;

  const currentPriority = Number(current.override_prioridade || 0);
  const incomingPriority = Number(incoming.override_prioridade || 0);

  return incomingPriority >= currentPriority ? incoming : current;
}

function buildIntroIfFirst(isFirstTurn) {
  if (!isFirstTurn) return [];

  return [
