function buildRaceQuestion(cao = {}) {
  const nome = hasValue(cao.nome) ? `do ${cao.nome}` : "dele";
  const original = clean(cao.regras_raca?.raca_original || cao.raca || "a raça informada");
  const candidates = parseArray(cao.regras_raca?.racas_candidatas)
    .map(item => clean(item.raca_canonica))
    .filter(Boolean)
    .filter((value, index, arr) => arr.indexOf(value) === index)
    .slice(0, 3);

  if (candidates.length >= 2) {
    const list = candidates.length === 2
      ? `${candidates[0]} ou ${candidates[1]}`
      : `${candidates.slice(0, -1).join(", ")} ou ${candidates[candidates.length - 1]}`;

    return `Pra eu não cadastrar errado: qual é a raça exata ${nome}? Para “${original}”, apareceram possibilidades como ${list}.`;
  }

  return `Pra eu não cadastrar errado: qual é a raça exata ${nome}? O nome “${original}” precisa ser confirmado antes de eu te orientar sobre os próximos passos.`;
}

function allBlockedByBreedAndNoPending(caes = []) {
  if (!caes.length) return false;
  return caes.every(cao => racaBloqueada(cao)) && !caes.some(cao => racaPendente(cao));
