const currentLeadMessage = clean(item.message?.content || item.chatInput || "");
const lastBruna = clean(item.message?.last_bruna_message_before_current_block || "");
const lastBrunaQuestion = clean(item.message?.last_bruna_question_before_current_block || "");
const history = clean(item.message?.history_for_crm || "");

if (shouldBlockImprovementFeedback(currentLeadMessage)) {
  item.should_reply = false;
  item.motivo_bloqueio_envio = "feedback_melhoria_bruna_nao_responder_lead";

  item.inputs = {
    ...(item.inputs || {}),
