      deve_solicitar_pagamento: false,
      deve_consultar_agenda: false,
      deve_criar_pre_reserva: false
    }
  };

  item.bruna_system_guard = item.inputs.bruna_system_guard;
  item.bruna_override = item.inputs.bruna_override;

  return item;
}

const turnSignals = isObject(item.inputs?.turn_signals)
  ? { ...item.inputs.turn_signals }
  : {};

let caes = getCaes()
  .filter(isObject)
  .map(normalizeDog)
  .filter(isRealDog);

const removedEmptyDogs = getCaes().length !== caes.length;

const resumoLead = sanitizeResumoLead(item.inputs?.resumo_lead || item.resumo_lead || {});

const frequency = normalizeFrequency(currentLeadMessage);
const hotelPeriod = parseSimplePeriodDays(currentLeadMessage);

if (frequency) {
  resumoLead.servico_interesse =
    resumoLead.servico_interesse && resumoLead.servico_interesse !== "nao_definido"
      ? resumoLead.servico_interesse
      : "creche";

  resumoLead.periodo_desejado = resumoLead.periodo_desejado || frequency;
}

if (hotelPeriod) {
  resumoLead.servico_interesse = "hotel";
  resumoLead.periodo_desejado = `período de ${hotelPeriod.start_day} a ${hotelPeriod.end_day}, ${hotelPeriod.diarias} diárias`;
}

const brunaHistory = extractBrunaMessagesFromHistory(history);
const lastTopic = questionTopic(lastBrunaQuestion || lastBruna);
const repeatCount = countRecentTopicRepeats(lastTopic, brunaHistory);
const leadComplained = leadComplainedAboutRepeat(currentLeadMessage);

const currentIsFrequencyOnly = isFrequencyOnly(currentLeadMessage);
const currentIsHotelPeriod = isHotelPeriod(currentLeadMessage);

const serviceInterest =
  resumoLead.servico_interesse ||
  item.inputs?.servico_interesse ||
  item.servico_interesse ||
  "nao_definido";

const hasService = ["creche", "hotel", "creche_e_hotel"].includes(serviceInterest);

const eligibilities = caes.map(dogEligibility);
const allKnownDogsEligible = caes.length > 0 && eligibilities.every(e => e.ok);
const hasAnyEligible = eligibilities.some(e => e.ok);

const adultMaleUnknownDogs = caes.filter(isAdultMaleCastrationUnknown);
const adultMaleNonCastratedDogs = caes.filter(isAdultMaleNonCastrated);
const femaleNonCastratedDogs = caes.filter(isFemaleNonCastrated);
const femaleInHeatDogs = caes.filter(cao => normalizeDog(cao).sexo === "femea" && normalizeDog(cao).no_cio === "sim");
const pendingRaceDogs = caes.filter(racaPendente);
const blockedRaceDogs = caes.filter(racaBloqueada);

const hasAdultMaleNonCastratedReal = adultMaleNonCastratedDogs.length > 0;
const hasAdultMaleUnknownReal = adultMaleUnknownDogs.length > 0;
const hasFemaleNonCastrated = femaleNonCastratedDogs.length > 0;

if (turnSignals.lead_informou_castrado_nao === true && !hasAdultMaleNonCastratedReal) {
  turnSignals.lead_informou_castrado_nao = false;
  turnSignals.lead_pretende_castrar = false;
  turnSignals.lead_nao_pretende_castrar = false;
}

if (hasFemaleNonCastrated && !hasAdultMaleNonCastratedReal) {
  turnSignals.lead_pretende_castrar = false;
  turnSignals.lead_nao_pretende_castrar = false;
}

let guard = {
  guard_version: "v5_macho_so_com_cao_real_primeira_mensagem_segura",

  anti_loop_acionado: false,
  motivo_loop: "",

  deve_forcar_humano: false,
  deve_forcar_apto: false,
  deve_bloquear_novo_cao_por_frequencia: currentIsFrequencyOnly && caes.length >= 1,

  removed_empty_dogs: removedEmptyDogs,
  topic_ultima_pergunta: lastTopic,
  repeat_count_topic: repeatCount,
  periodo_hotel_detectado: hotelPeriod || null,
  frequencia_detectada: frequency || "",

  quantidade_caes_reais: caes.length,

  flags_castracao: {
    has_adult_male_unknown: hasAdultMaleUnknownReal,
    has_adult_male_non_castrated: hasAdultMaleNonCastratedReal,
    has_female_non_castrated: hasFemaleNonCastrated,
    lead_informou_castrado_nao: turnSignals.lead_informou_castrado_nao === true,
    lead_pretende_castrar: turnSignals.lead_pretende_castrar === true,
    lead_nao_pretende_castrar: turnSignals.lead_nao_pretende_castrar === true
  },

  flags_raca: {
    pendentes: pendingRaceDogs.length,
    bloqueadas: blockedRaceDogs.length,
    todas_bloqueadas_sem_pendente: allBlockedByBreedAndNoPending(caes)
  },

  motivo_bloqueio_apto: "",
  motivos_bloqueio_apto: []
};

let override = {};

if (turnSignals.lead_confirmou_humano === true) {
  guard.deve_forcar_humano = true;

  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "TRANSFERIDO_FLAVIA",
      ultima_intencao: "PEDIU_HUMANO",
      evento_sistema: "REPASSE_FLAVIA",
      proxima_acao: "repassar_humano",
      deve_repassar_humano: true,
      motivo_repasse: "lead_confirmou_atendimento_humano",
      prioridade: 130,
      motivo: "lead_confirmou_humano",
      mensagens_resposta: [
        "Combinado. Vou passar para uma pessoa da equipe te atender em horário comercial."
      ]
    })
  );
}

if (turnSignals.lead_finalizou_atendimento === true) {
  guard.deve_forcar_humano = true;

  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "TRANSFERIDO_FLAVIA",
      ultima_intencao: "PEDIU_HUMANO",
      evento_sistema: "REPASSE_FLAVIA",
      proxima_acao: "repassar_para_humano_atendimento_finalizado",
      deve_repassar_humano: true,
      motivo_repasse: "lead_finalizou_atendimento_encaminhar_humano",
      prioridade: 125,
      motivo: "lead_finalizou_atendimento",
      mensagens_resposta: [
        "Tudo certo. Vou deixar seu atendimento encaminhado para uma pessoa da equipe, caso precisem dar continuidade em horário comercial."
      ]
    })
  );
}

if (turnSignals.lead_pretende_castrar === true) {
  guard.deve_forcar_humano = true;

  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "TRANSFERIDO_FLAVIA",
      ultima_intencao: "MACHO_NAO_CASTRADO",
      evento_sistema: "REPASSE_FLAVIA",
      proxima_acao: "repassar_humano_macho_tutor_pretende_castrar",
      deve_repassar_humano: true,
      motivo_repasse: "macho_nao_castrado_tutor_pretende_castrar",
      prioridade: 122,
      motivo: "lead_pretende_castrar",
      mensagens_resposta: [
        "Entendi. Como você pretende castrar, vou passar para uma pessoa especialista da equipe te orientar sobre o melhor próximo passo em horário comercial."
      ]
    })
  );
}

if (turnSignals.lead_nao_pretende_castrar === true) {
  if (hasAdultMaleNonCastratedReal) {
    override = chooseOverride(
      override,
      buildOverride({
        status_lead: "ENCERRADO_NAO_PERFIL",
        ultima_intencao: "MACHO_NAO_CASTRADO",
        evento_sistema: "CONVERSA_ENCERRADA",
        apto_para_avaliacao: "nao",
        proxima_acao: "encerrar_nao_perfil_macho_nao_castrado",
        deve_repassar_humano: false,
        deve_encerrar_conversa: true,
        prioridade: 118,
        motivo: "macho_adulto_nao_castrado_tutor_nao_pretende_castrar",
        mensagens_resposta: [
          "Entendi. Pela regra da AuAu, machos a partir de 8 meses precisam ser castrados para frequentar a creche ou hospedagem em grupo. Nesse caso, infelizmente não conseguimos seguir com o atendimento para ele agora."
        ]
      })
    );
  } else {
    guard.motivos_bloqueio_apto.push("lead_nao_pretende_castrar_ignorado_sem_macho_adulto_nao_castrado_real");
    turnSignals.lead_nao_pretende_castrar = false;
  }
}

if (leadComplained || repeatCount >= 3) {
  guard.anti_loop_acionado = true;
  guard.deve_forcar_humano = true;
  guard.motivo_loop = leadComplained
    ? "lead_reclamou_de_repeticao"
    : `pergunta_repetida_${lastTopic}_${repeatCount}_vezes`;

  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "TRANSFERIDO_FLAVIA",
      ultima_intencao: "PEDIU_HUMANO",
      evento_sistema: "REPASSE_FLAVIA",
      proxima_acao: "repassar_para_humano_por_loop",
      deve_repassar_humano: true,
      motivo_repasse: "Loop de atendimento detectado. A Bruna repetiu perguntas ou o lead sinalizou que já respondeu.",
      prioridade: 115,
      motivo: guard.motivo_loop,
      mensagens_resposta: [
        "Percebi que posso estar repetindo algumas perguntas por aqui. Para não travar seu atendimento, vou passar para uma pessoa especialista da equipe continuar com você em horário comercial."
      ]
    })
  );
}

if (
  hasFemaleNonCastrated &&
  !hasAdultMaleNonCastratedReal &&
  !guard.deve_forcar_humano
) {
  const femea = femaleNonCastratedDogs[0];
  const nome = femalePronoun(femea);

  const precisaPerguntarCio =
    normalizeDog(femea).no_cio === "nao_informado";

  const precisaSanitario =
    !hasSanitario(femea);

  let pergunta = "";

  if (precisaPerguntarCio && precisaSanitario) {
    pergunta = `Anotei ${nome}. Para fêmeas, a castração não é bloqueio na AuAu. Ela está no cio atualmente? E vacinas, antipulgas e vermifugação estão em dia?`;
  } else if (precisaPerguntarCio) {
    pergunta = `Anotei ${nome}. Para fêmeas, a castração não é bloqueio na AuAu. Ela está no cio atualmente?`;
  } else if (precisaSanitario) {
    pergunta = `Anotei ${nome}. Para fêmeas, a castração não é bloqueio na AuAu. Vacinas, antipulgas e vermifugação estão em dia?`;
  } else {
    pergunta = `Anotei ${nome}. Para fêmeas, a castração não é bloqueio na AuAu. Vou seguir com a qualificação dela.`;
  }

  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "QUALIFICANDO",
      ultima_intencao: "INFORMOU_DADOS_CAO",
      evento_sistema: "",
      apto_para_avaliacao: "pendente",
      proxima_acao: precisaPerguntarCio || precisaSanitario
        ? "perguntar_cio_e_dados_sanitarios_femea"
        : "seguir_qualificacao_femea_nao_castrada",
      deve_repassar_humano: false,
      prioridade: 112,
      motivo: "femea_nao_castrada_nao_e_bloqueio",
      mensagens_resposta: [
        ...buildIntroIfFirst(shouldForceFirstTurnIntro(item, history)),
        pergunta
      ]
    })
  );
}

if (
  hasAdultMaleUnknownReal &&
  !guard.deve_forcar_humano &&
  !turnSignals.lead_pretende_castrar &&
  !turnSignals.lead_nao_pretende_castrar
) {
  const cao = adultMaleUnknownDogs[0];
  const nome = malePronoun(cao);

  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "COLETANDO_DADOS",
      ultima_intencao: "INFORMOU_DADOS_CAO",
      evento_sistema: "",
      apto_para_avaliacao: "pendente",
      proxima_acao: "aguardar_confirmacao_castracao_status",
      deve_repassar_humano: false,
      prioridade: 110,
      motivo: "macho_adulto_com_castracao_nao_informada",
      mensagens_resposta: [
        ...buildIntroIfFirst(shouldForceFirstTurnIntro(item, history)),
        `Me confirma uma coisa importante: ${nome} é castrado?`
      ]
    })
  );
}

if (
  hasAdultMaleNonCastratedReal &&
  !guard.deve_forcar_humano &&
  !turnSignals.lead_pretende_castrar &&
  !turnSignals.lead_nao_pretende_castrar
) {
  const cao = adultMaleNonCastratedDogs[0];
  const nome = malePronoun(cao);

  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "PRE_REPROVADO",
      ultima_intencao: "MACHO_NAO_CASTRADO",
      evento_sistema: "",
      apto_para_avaliacao: "pendente",
      proxima_acao: "aguardar_intencao_castracao",
      deve_repassar_humano: false,
      prioridade: 108,
      motivo: "macho_adulto_nao_castrado_confirmar_intencao",
      mensagens_resposta: [
        ...buildIntroIfFirst(shouldForceFirstTurnIntro(item, history)),
        `Pela regra da AuAu, machos a partir de 8 meses precisam ser castrados para frequentar a rotina em grupo. Você pretende castrar ${nome}?`
      ]
    })
  );
}

if (
  pendingRaceDogs.length > 0 &&
  !guard.deve_forcar_humano
) {
  const pending = firstPendingRaceDog(caes);

  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "COLETANDO_DADOS",
      ultima_intencao: "INFORMOU_DADOS_CAO",
      evento_sistema: "",
      apto_para_avaliacao: "pendente",
      proxima_acao: "aguardar_confirmacao_raca",
      deve_repassar_humano: false,
      prioridade: 85,
      motivo: "raca_pendente_precisa_confirmacao_antes_decisao",
      mensagens_resposta: [
        ...buildIntroIfFirst(shouldForceFirstTurnIntro(item, history)),
        buildRaceQuestion(pending)
      ]
    })
  );
}

if (
  allBlockedByBreedAndNoPending(caes) &&
  !guard.deve_forcar_humano
) {
  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "ENCERRADO_NAO_PERFIL",
      ultima_intencao: "RACA_POTENCIAL_DANO",
      evento_sistema: "CONVERSA_ENCERRADA",
      apto_para_avaliacao: "nao",
      proxima_acao: "encerrar_nao_perfil_raca_potencial_dano",
      deve_repassar_humano: false,
      deve_encerrar_conversa: true,
      prioridade: 82,
      motivo: "todos_caes_bloqueados_por_raca_conclusiva",
      mensagens_resposta: [
        ...buildIntroIfFirst(shouldForceFirstTurnIntro(item, history)),
        "Entendo. Essa regra não é um julgamento individual do cão e não significa que ele seja agressivo. É uma regra operacional de segurança da AuAu para ambiente coletivo, onde vários cães convivem juntos. Por isso, para essa raça específica, infelizmente não conseguimos seguir com creche ou hotel."
      ]
    })
  );
}

if (
  femaleInHeatDogs.length > 0 &&
  !guard.deve_forcar_humano &&
  !allBlockedByBreedAndNoPending(caes)
) {
  const femea = femaleInHeatDogs[0];
  const nome = femalePronoun(femea);

  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "QUALIFICANDO",
      ultima_intencao: "INFORMOU_DADOS_CAO",
      evento_sistema: "",
      apto_para_avaliacao: "pendente",
      proxima_acao: "orientar_femea_no_cio_e_continuar_qualificacao",
      deve_repassar_humano: false,
      prioridade: 78,
      motivo: "femea_no_cio_nao_e_nao_perfil_definitivo",
      mensagens_resposta: [
        ...buildIntroIfFirst(shouldForceFirstTurnIntro(item, history)),
        `Nesse período, ${nome} não pode frequentar creche, hotel ou adaptação em grupo. Mas isso não é bloqueio definitivo; a gente pode seguir a orientação para quando ela sair do cio.`
      ]
    })
  );
}

if (
  hasService &&
  caes.length > 0 &&
  allKnownDogsEligible &&
  !guard.deve_forcar_humano &&
  !allBlockedByBreedAndNoPending(caes)
) {
  guard.deve_forcar_apto = true;

  override = chooseOverride(
    override,
    buildOverride({
      status_lead: "APTO_PARA_AVALIACAO",
      ultima_intencao: "ACEITOU_AVALIACAO",
      evento_sistema: "REPASSE_FLAVIA",
      apto_para_avaliacao: "sim",
      proxima_acao: "repassar_para_humano_explicar_avaliacao_e_proximos_passos",
      deve_repassar_humano: true,
      motivo_repasse: "Lead chegou aos critérios mínimos para avaliação comportamental. Encaminhar para especialista humano orientar próximos passos.",
      deve_solicitar_pagamento: false,
      prioridade: 70,
      motivo: "apto_para_avaliacao_com_criterios_minimos_completos",
      mensagens_resposta: [
        "Com essas informações, o próximo passo é a avaliação comportamental. Ela custa R$ 100 e serve para a equipe entender se o cãozinho fica bem na rotina em grupo com segurança.",
        "Se ele for aprovado, esse valor fica como crédito no processo de adaptação; se não for aprovado, o valor é devolvido via PIX. Vou passar para uma pessoa especialista da equipe continuar com você em horário comercial."
      ]
    })
  );
}

if (
  hasService &&
  caes.length > 0 &&
  !allKnownDogsEligible
) {
  const motivos = [];

  eligibilities.forEach((e, index) => {
    if (!e.hasBasic) motivos.push(`cao_${index}_dados_basicos_incompletos`);
    if (!e.hasSanitario) motivos.push(`cao_${index}_sanitario_incompleto`);
    if (!e.hasComportamento) motivos.push(`cao_${index}_comportamento_incompleto`);
    if (e.racaPendente) motivos.push(`cao_${index}_raca_pendente`);
    if (e.racaBloqueada) motivos.push(`cao_${index}_raca_bloqueada`);
    if (!e.racaOk) motivos.push(`cao_${index}_raca_nao_conclusiva`);
    if (e.machoAdultoNaoCastrado) motivos.push(`cao_${index}_macho_adulto_nao_castrado`);
    if (e.machoAdultoCastracaoNaoInformada) motivos.push(`cao_${index}_castracao_macho_adulto_incompleta`);
    if (e.femeaNoCio) motivos.push(`cao_${index}_femea_no_cio_temporario`);
  });

  guard.motivo_bloqueio_apto = motivos.join("|");
  guard.motivos_bloqueio_apto = motivos;
}

if (
  turnSignals.lead_informou_castrado_nao === false &&
  hasFemaleNonCastrated &&
  !hasAdultMaleNonCastratedReal
) {
  guard.motivos_bloqueio_apto = [
    ...(guard.motivos_bloqueio_apto || []),
    "femea_nao_castrada_nao_bloqueia"
  ];
}

if (override.deve_solicitar_pagamento === true) {
  override.deve_solicitar_pagamento = false;
}

if (override.deve_consultar_agenda === true) {
  override.deve_consultar_agenda = false;
}

if (override.deve_criar_pre_reserva === true) {
  override.deve_criar_pre_reserva = false;
}

const finalInputs = {
  ...(item.inputs || {}),

  caes_json: caes,
  quantidade_caes: caes.length,

  resumo_lead: resumoLead,

  turn_signals: turnSignals,

  bruna_system_guard: guard,
  bruna_override: override,

  deve_repassar_humano: override.deve_repassar_humano === true
    ? true
    : item.inputs?.deve_repassar_humano === true,

  motivo_repasse: override.motivo_repasse || item.inputs?.motivo_repasse || "",

  proxima_acao: override.proxima_acao || item.inputs?.proxima_acao || "",

  apto_para_avaliacao: override.apto_para_avaliacao || item.inputs?.apto_para_avaliacao || "pendente",

  deve_solicitar_pagamento: false,
  deve_consultar_agenda: false,
  deve_criar_pre_reserva: false,
  pre_reserva_criada: false,
  data_hora_avaliacao: "",
  data_hora_pre_reserva: ""
};

item.inputs = finalInputs;

item.caes_json = caes;
item.quantidade_caes = caes.length;
item.resumo_lead = resumoLead;
item.bruna_system_guard = guard;
item.bruna_override = override;

item.debug_contexto = {
  ...(item.debug_contexto || {}),
  guard_rail_sistemico_bruna: {
    version: guard.guard_version,
    quantidade_caes_reais: caes.length,
    removed_empty_dogs: removedEmptyDogs,
    has_service: hasService,
    service_interest: serviceInterest,
    current_is_frequency_only: currentIsFrequencyOnly,
    current_is_hotel_period: currentIsHotelPeriod,
    frequency_detected: frequency || "",
    hotel_period_detected: hotelPeriod || null,

    adult_male_unknown_count: adultMaleUnknownDogs.length,
    adult_male_non_castrated_count: adultMaleNonCastratedDogs.length,
    female_non_castrated_count: femaleNonCastratedDogs.length,
    pending_race_count: pendingRaceDogs.length,
    blocked_race_count: blockedRaceDogs.length,

    all_known_dogs_eligible: allKnownDogsEligible,
    has_any_eligible: hasAnyEligible,

    override_aplicado: isObject(override) && Object.keys(override).length > 0,
    override_prioridade: override.override_prioridade || 0,
    override_motivo: override.motivo_override || "",

    guard
  }
};

return item;
